10	const PROCESSING_FEE = 5;
11	const INITIAL_ASSESSMENT_MULTIPLIER = 1.1;
12	const ALIKE_BUNDLE_DISCOUNT = 15;
13	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
14	const HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER = 1.3;
15	const HIGH_ENCHANTMENT_THRESHOLD = 5;
16	const COMPONENT_TYPES = ["rune", "moonstone"];
17	
18	type Item = { type: string; cursed?: boolean; enchantment?: number };
19	
20	function ceilToWholeGold(amount: number): number {
21	  return Math.ceil(Math.round(amount * 1e6) / 1e6);
22	}
23	
24	function basePremiumFor(itemType: string): number {
25	  return BASE_PREMIUMS[itemType] ?? 0;
26	}
27	
28	function isHighlyEnchanted(item: Item): boolean {
29	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
30	}
31	
32	function itemPremium(item: Item): number {
33	  const base = basePremiumFor(item.type);
34	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE_MULTIPLIER : 1;
35	  const enchantmentMultiplier = isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER : 1;
36	  return base * cursedMultiplier * enchantmentMultiplier;
37	}
38	
39	function countOfType(items: Array<Item>, itemType: string): number {
40	  return items.filter((item) => item.type === itemType).length;
41	}
42	
43	function alikeBundleDiscount(items: Array<Item>): number {
44	  const bundleCount = COMPONENT_TYPES.reduce(
45	    (sum, componentType) => sum + Math.floor(countOfType(items, componentType) / 3),
46	    0,
47	  );
48	  return bundleCount * ALIKE_BUNDLE_DISCOUNT;
49	}
50	
51	export function quote(input: { items: Array<Item> }): number {
52	  const itemPremiumSum = input.items.reduce((sum, item) => sum + itemPremium(item), 0);
53	  const itemsTotal = itemPremiumSum - alikeBundleDiscount(input.items);
54	  const total = itemsTotal * INITIAL_ASSESSMENT_MULTIPLIER + PROCESSING_FEE;
55	  return ceilToWholeGold(total);
56	}
